<?php $sql = "EXPLAIN SELECT w.name AS warehouse_name, COUNT(DISTINCT pw.product_id) AS total_distinct_products, SUM(p.unit_price * pw.quantity_on_hand) AS total_stock_value, (SELECT p_sm.name FROM stock_movements sm JOIN products p_sm ON sm.product_id = p_sm.id WHERE sm.warehouse_id = w.id ORDER BY sm.created_at DESC LIMIT 1) AS most_recently_moved_product, (SELECT sm.created_at FROM stock_movements sm WHERE sm.warehouse_id = w.id ORDER BY sm.created_at DESC LIMIT 1) AS most_recent_movement_date FROM warehouses w LEFT JOIN product_warehouse pw ON w.id = pw.warehouse_id AND pw.quantity_on_hand > 0 LEFT JOIN products p ON pw.product_id = p.id WHERE w.is_active = 1 GROUP BY w.id, w.name"; print_r(DB::select($sql));
